import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { WebhookHandler, resetWebhookIdCounters } from '../../src/notifications/webhook-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
    ...overrides,
  };
}

function makeStatusChangedEvent(
  previousStatus: string,
  newStatus: string,
  orderId = 'order-1',
): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: orderId,
      userId: 'user-1',
      items: [],
      total: 20,
      status: newStatus as OrderStatusChangedEvent['order']['status'],
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus,
    newStatus,
    timestamp: new Date(),
  };
}

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let handler: WebhookHandler;

  beforeEach(() => {
    resetWebhookIdCounters();
    eventBus = new EventBus();
    handler = new WebhookHandler(eventBus);
  });

  describe('webhook registration', () => {
    it('should register a webhook for an event type', () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created');

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.registeredAt).toBeInstanceOf(Date);
    });

    it('should register a webhook with a secret', () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created', 'my-secret');

      expect(reg.secret).toBe('my-secret');
    });

    it('should register multiple webhooks for the same event type', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      expect(handler.getRegistrations()).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
    });

    it('should register webhooks for different event types', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(1);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created');

      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering a non-existent webhook', () => {
      expect(handler.unregisterWebhook('webhook-9999')).toBe(false);
    });
  });

  describe('order:created webhooks', () => {
    it('should deliver to registered webhooks when order is created', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
      expect(deliveries[0]?.eventType).toBe('order:created');
      expect(deliveries[0]?.success).toBe(true);
    });

    it('should include order details in the payload', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const payload = handler.getDeliveries()[0]!.payload;
      expect(payload.orderId).toBe('order-1');
      expect(payload.userId).toBe('user-1');
      expect(payload.userEmail).toBe('alice@example.com');
      expect(payload.total).toBe(20);
      expect(payload.status).toBe('pending');
      expect(payload.eventType).toBe('order:created');
    });

    it('should deliver to multiple webhooks for the same event', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveries()).toHaveLength(2);
    });

    it('should not deliver to webhooks registered for other events', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveries()).toHaveLength(0);
    });
  });

  describe('order:status-changed webhooks', () => {
    it('should deliver to registered webhooks when status changes', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
      expect(deliveries[0]?.eventType).toBe('order:status-changed');
    });

    it('should include status details in the payload', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed', 'order-42'));

      const payload = handler.getDeliveries()[0]!.payload;
      expect(payload.orderId).toBe('order-42');
      expect(payload.previousStatus).toBe('pending');
      expect(payload.newStatus).toBe('confirmed');
      expect(payload.eventType).toBe('order:status-changed');
    });

    it('should deliver for all status transitions', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));
      await eventBus.emit(makeStatusChangedEvent('shipped', 'delivered'));

      expect(handler.getDeliveries()).toHaveLength(3);
    });
  });

  describe('delivery tracking', () => {
    it('should track delivery count', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      expect(handler.getDeliveryCount()).toBe(0);

      await eventBus.emit(makeOrderCreatedEvent());
      expect(handler.getDeliveryCount()).toBe(1);
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveriesForWebhook(reg1.id)).toHaveLength(1);
      expect(handler.getDeliveriesForWebhook(reg1.id)[0]?.url).toBe('https://a.com/hook');
    });

    it('should clear registrations and deliveries', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      handler.clear();

      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveries()).toHaveLength(0);
    });
  });

  describe('integration with EventBus', () => {
    it('should handle the full order lifecycle', async () => {
      handler.registerWebhook('https://example.com/created', 'order:created');
      handler.registerWebhook('https://example.com/status', 'order:status-changed');

      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));
      await eventBus.emit(makeStatusChangedEvent('shipped', 'delivered'));

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(4);
      expect(deliveries[0]?.url).toBe('https://example.com/created');
      expect(deliveries[1]?.url).toBe('https://example.com/status');
      expect(deliveries[2]?.url).toBe('https://example.com/status');
      expect(deliveries[3]?.url).toBe('https://example.com/status');
    });

    it('should coexist with NotificationService on the same EventBus', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      resetNotificationIdCounter();
      const notifService = new NotificationService(eventBus);

      handler.registerWebhook('https://example.com/hook', 'order:status-changed');
      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      expect(handler.getDeliveryCount()).toBe(1);
      expect(notifService.getNotificationCount()).toBe(1);
    });

    it('should coexist with EmailNotificationHandler on the same EventBus', async () => {
      const { EmailNotificationHandler } = await import(
        '../../src/notifications/email-handler.js'
      );
      const emailHandler = new EmailNotificationHandler(eventBus);

      handler.registerWebhook('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveryCount()).toBe(1);
      expect(emailHandler.getSentCount()).toBe(1);
    });

    it('should not deliver after webhook is unregistered', async () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created');
      handler.unregisterWebhook(reg.id);

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveries()).toHaveLength(0);
    });

    it('should log events in the EventBus event log', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      const log = eventBus.getEventLog();
      expect(log).toHaveLength(1);
      expect(log[0]?.type).toBe('order:created');
    });
  });
});

